// Fan out one item per uploaded image, rename its binary to "data",
// and carry a base64 data URI so we can show the image on the result screen
const out = [];
const inputItems = $input.all();
let counter = 0;

for (let itemIndex = 0; itemIndex < inputItems.length; itemIndex++) {
  const item = inputItems[itemIndex];
  const binaries = item.binary || {};
  const productName = item.json['Product Name'] || item.json.productName || '';
  const keys = Object.keys(binaries);

  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    const bin = binaries[key];
    counter += 1;

    const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, key);
    const mimeType = bin.mimeType || 'image/jpeg';
    const dataUri = `data:${mimeType};base64,${buffer.toString('base64')}`;

    out.push({
      json: {
        productName,
        imageIndex: counter,
        fileName: bin.fileName || `image_${counter}`,
        mimeType,
        dataUri,
      },
      binary: { data: bin },
      pairedItem: { item: 0 },
    });
  }
}

return out;

const results = $input.all();
const inputs  = $('Code: Expand images into items').all();

const isMissing = (v) => {
  if (v === null || v === undefined) return true;
  const s = String(v).trim().toLowerCase();
  return s === '' || s === 'null';
};
const esc = (s) => String(s)
  .replace(/&/g,'&amp;').replace(/</g,'&lt;')
  .replace(/>/g,'&gt;').replace(/"/g,'&quot;');

const blocks = [];
results.forEach((res, i) => {
  const d = res.json.data || res.json || {};
  const meta = (inputs[i] && inputs[i].json) || {};

  const fileName = isMissing(meta.fileName) ? `Image ${i+1}` : String(meta.fileName).trim();
  const dataUri  = isMissing(meta.dataUri) ? '' : meta.dataUri;
  const rawDesc  = isMissing(d.description) ? '' : String(d.description).trim();

  const unclear = (rawDesc === '' || rawDesc.toUpperCase() === 'UNCLEAR');
  const body = unclear
    ? 'We could not generate a description for this image. Try a clearer, well-lit photo of a single product.'
    : rawDesc;

  const img = dataUri
    ? `<img src="${dataUri}" alt="${esc(fileName)}" style="width:120px;height:120px;object-fit:cover;border-radius:8px;flex-shrink:0;border:1px solid #eee;" />`
    : '';

  const copyBtn = unclear ? '' :
    `<button type="button"
       onclick="(function(b){navigator.clipboard.writeText(b.getAttribute('data-copy')).then(function(){var t=b.innerText;b.innerText='Copied';setTimeout(function(){b.innerText=t;},1500);});})(this)"
       data-copy="${esc(body)}"
       style="margin-top:10px;padding:6px 14px;font-size:13px;font-weight:600;color:#111;background:#fff;border:1px solid #111;border-radius:6px;cursor:pointer;">
       Copy description
     </button>`;

  blocks.push(
    `<div style="display:flex;gap:16px;align-items:flex-start;flex-wrap:wrap;margin:0 0 20px 0;padding:0 0 20px 0;border-bottom:1px solid #ececec;">
       ${img}
       <div style="flex:1;min-width:220px;">
         <p style="margin:0 0 6px 0;font-weight:600;color:#111;">${esc(fileName)}</p>
         <p style="margin:0;line-height:1.55;color:${unclear ? '#b00' : '#333'};">${esc(body)}</p>
         ${copyBtn}
       </div>
     </div>`
  );
});

const heading = results.length === 1 ? 'Your image description is ready' : 'Your image descriptions are ready';

const html =
  `<div style="max-width:680px;margin:0 auto;padding:32px 20px 48px 20px;text-align:left;font-family:inherit;">
     <h2 style="margin:0 0 16px 0;font-size:22px;font-weight:700;color:#111;">${heading}</h2>
     ${blocks.join('\n')}
   </div>`;

return [{ json: { imageCount: results.length, combinedDescription: html } }];
